import React, { useState } from 'react';
import { FiMessageSquare, FiSend } from 'react-icons/fi';
import { generateDynamicData } from '../../utils/dynamicData';

interface Props { skillId?: string; }

const AIMentorChat: React.FC<Props> = ({ skillId }) => {
  const data = generateDynamicData(skillId);
  const [messages, setMessages] = useState([
    { text: `Hi! I'm your AI Mentor. I see you're interested in ${data.skill}. What would you like to know about learning it?`, isAi: true }
  ]);
  const [input, setInput] = useState('');

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setMessages([...messages, { text: input, isAi: false }]);
    setInput('');

    setTimeout(() => {
      setMessages(prev => [...prev, { 
        text: `Based on your profile, learning ${data.skill} is a great choice. You should start with the official documentation and practice building small projects to reduce your ${data.decayRate}% decay rate.`, 
        isAi: true 
      }]);
    }, 1000);
  };

  return (
    <div className="animate-fadeIn">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col h-[500px]">
        <div className="bg-slate-50 border-b border-gray-200 p-4">
          <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
            <FiMessageSquare className="text-blue-500" /> AI Career Mentor
          </h3>
        </div>

        <div className="flex-grow p-4 overflow-y-auto space-y-4 bg-white">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.isAi ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl ${
                msg.isAi ? 'bg-blue-50 text-blue-900 rounded-tl-none border border-blue-100' : 'bg-slate-800 text-white rounded-tr-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <form onSubmit={handleSend} className="p-4 bg-gray-50 border-t border-gray-200 flex gap-2">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask about your learning path..."
            className="flex-grow bg-white border border-gray-300 rounded-xl px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
          />
          <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-colors shadow-sm">
            <FiSend />
          </button>
        </form>
      </div>
    </div>
  );
};

export default AIMentorChat;
